import React, {useState} from 'react'
import ReactPlayer from "react-player";
import ScrollAnimation from "react-animate-on-scroll";
import Modal from 'react-modal';

const customStyles = {
    content : {
        top                   : '50%',
        left                  : '50%',
        right                 : 'auto',
        bottom                : 'auto',
        marginRight           : '-50%',
        transform             : 'translate(-50%, -50%)'
    }
};

const Projects = () => {
    const [isShown, SetIsShown] = useState(0);
    const [isPlayable,SetPlayable] = useState(0);
    var subtitle;
    const [modalIsOpen,setIsOpen] = useState(0);
    function openModal() {
        setIsOpen(true);
    }

    function afterOpenModal() {
        // references are now sync'd and can be accessed.
        subtitle.style.color = '#f00';
    }

    function closeModal(){
        setIsOpen(false);
    }
    return(
        <div className="ui center aligned segment" id="project">
            <div className="ui centered grid">
                <div className="cell"
                     onMouseEnter={() => (SetIsShown(1),SetPlayable(1))}
                     onMouseLeave={() => (SetIsShown(0),SetPlayable(0))}
                     onClick={()=>(SetIsShown(1),SetPlayable(1))}
                >
                    {modalIsOpen!==1 && (
                        <div>
                            <button
                                className="ui orange inverted button demo1"
                                onClick={() => setIsOpen(1)}
                                style={{opacity:isShown===1 ? 1:0,transition: "opacity 1s",zIndex:"5"}}>Learn More</button>
                        </div>
                    )

                    }
                    <ReactPlayer
                        url="videos/Helicopter_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        volume={1}
                        muted={true}
                        loop={false}
                        playing={isPlayable===1 ? 0:1}
                        // controls={isPlayable==1 ? 0 : 1}
                        controls={true}
                    ></ReactPlayer>
                    {modalIsOpen===1 && (
                        <Modal
                            isOpen={modalIsOpen}
                            onRequestClose={()=>setIsOpen(0)}
                            style={customStyles}
                            contentLabel="Example Modal"

                        >
                            <div className="ui segment" style={{width:"40vw",height:"40vh",zIndex:"6"}}>
                                <h2>Helicopter Simulation</h2>
                                <h4>Written in: C++ and OpenGL </h4>
                                <div className="grid">
                                    <div className="cell">
                                        <p>Check out the repository: </p>
                                    </div>
                                    <div className="cell">
                                        <a href="https://github.com/DMZnoo/Helicopter" target="_blank">REPO</a>
                                    </div>
                                </div>
                            </div>
                            <div className="ui vertical segment">
                                <button className="ui red inverted button" onClick={closeModal}>close</button>
                            </div>

                        </Modal>
                    )

                    }
                </div>
                <div className="cell"
                     onMouseEnter={() => (SetIsShown(2),SetPlayable(2))}
                     onMouseLeave={() => (SetIsShown(0),SetPlayable(0))}
                >
                    {modalIsOpen!==2 && (
                        <div>
                            <button
                                className="ui orange inverted button demo2"
                                onClick={() => setIsOpen(2)}
                                style={{opacity:isShown===2 ? 2:0,transition: "opacity 1s",zIndex:"5"}}>Learn More</button>
                        </div>
                    )

                    }

                    <ReactPlayer
                        url="videos/Solar_System_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        volume={1}
                        muted={true}
                        loop={false}
                        playing={isPlayable===2 ? 0:2}
                        controls={true}
                    ></ReactPlayer>
                    {modalIsOpen===2 && (
                        <Modal
                            isOpen={modalIsOpen}
                            onRequestClose={()=>setIsOpen(0)}
                            style={customStyles}
                            contentLabel="Example Modal"
                        >
                            <div className="ui segment" style={{width:"40vw",height:"40vh",zIndex:"6"}}>
                                <h2>Solar System Simulation</h2>
                                <h4>Written in: C++ and OpenGL </h4>
                                <div className="grid">
                                    <div className="cell">
                                        <p>Check out the repository: </p>
                                    </div>
                                    <div className="cell">
                                        <a href="https://github.com/DMZnoo/Solar_System" target="_blank">REPO</a>
                                    </div>
                                </div>
                            </div>
                            <div className="ui vertical segment">
                                <button className="ui red inverted button" onClick={closeModal}>close</button>
                            </div>

                        </Modal>
                    )

                    }

                </div>
            </div>
        </div>
    );
};
export default Projects;
